set unit_name = #{unitName}, contact_person = #{contactPerson}, contact_number = #{contactNumber}, social_num = #{socialNum},
    register_addr = #{registerAddr}, cert_start = #{certStart}, cert_end = #{certEnd}, serv_item = #{servItem}, extra_info = #{extraInfoStr}
